sql:
SELECT type_name
FROM sample_types
WHERE type_id = 1;

SELECT COUNT(sample_id)
FROM glass_samples
WHERE status = 'active';

SELECT sample_name
FROM glass_samples
WHERE type_id = 0;

SELECT lab_name, lab_location
FROM labs
WHERE lab_id = 0;

SELECT sample_name, AVG(refractive_index) AS avg_refractive_index
FROM glass_samples
GROUP BY sample_name;

SELECT sample_id, AVG(refractive_index) AS average_refractive_index
FROM glass_samples
GROUP BY sample_id;

SELECT sample_id
FROM glass_samples
WHERE status = 'active';

SELECT COUNT(sample_id) AS sample_count
FROM glass_samples
WHERE type_id = (SELECT type_id FROM sample_types WHERE type_name = 'Float Glass');

SELECT sample_name
FROM glass_samples
ORDER BY collection_date ASC, sample_name ASC;

SELECT sample_name
FROM glass_samples
WHERE refractive_index > 1.52;

external_knowledge:
Glass samples can originate from various sources; 
A sample's status could indicate if it's active or archived;
Chemical composition can be crucial for identifying the type and properties of the glass;
Modification history is essential for tracking changes and approvals;
Access logs help monitor who accessed the samples and how.
